      sampleInput: "nums = [1, 3, 4, 2, 2]",
      sampleOutput: "duplicate number = 2.",
      steps: [
        { title: "View values as pointers", state: "The path is 0 -> 1 -> 3 -> 2 -> 4 -> 2.", explanation: "Following values creates a loop. The value 2 is where the loop begins, which is why it is the duplicate.", variables: { path: "0->1->3->2->4->2" } },
        { title: "Start both runners", state: "slow = nums[0] = 1, fast = nums[0] = 1.", explanation: "Both runners start inside the value graph and move by following nums[value].", variables: { slow: "1", fast: "1" } },
        { title: "First chase step", state: "slow moves to nums[1] = 3. fast moves to nums[nums[1]] = nums[3] = 2.", explanation: "Fast moves two links at a time, so it begins closing the distance inside the eventual cycle.", variables: { slow: "3", fast: "2" } },
        { title: "They meet inside the cycle", state: "slow moves to nums[3] = 2. fast moves from 2 to nums[nums[2]] = nums[4] = 2.", explanation: "Meeting at 2 proves we are in the cycle, but we still need the cycle entry proof.", variables: { slow: "2", fast: "2" } },
        { title: "Reset one runner", state: "Set slow back to nums[0] = 1, keep fast at 2.", explanation: "Now both move one step at a time. Floyd's distance relationship makes them meet at the entry.", variables: { slow: "1", fast: "2" } },
        { title: "Walk to the entry", state: "slow: 1 -> 3 -> 2. fast: 2 -> 4 -> 2. They meet at 2.", explanation: "The cycle entry is the value receiving multiple incoming links, which is exactly the duplicate number.", variables: { duplicate: "2" } },
      ],
      closingInsight: "The duplicate is found as the entry point of the cycle created by value-as-index pointers, not by sorting or marking the array.",
