      steps: [
        { title: "Initialize source", state: "dist[1] = 0, parent[1] = 1, heap = (0,1).", explanation: "The source starts with zero cost and points to itself for path reconstruction.", variables: { dist1: "0" } },
        { title: "Relax from 1", state: "Update dist[2] = 2 and dist[4] = 1.", explanation: "Both neighbors are reachable directly from node 1.", variables: { dist: "2:2, 4:1" } },
        { title: "Choose cheapest frontier", state: "Pop node 4 with cost 1 before node 2 with cost 2.", explanation: "Dijkstra always expands the cheapest known route first.", variables: { current: "4" } },
        { title: "Improve through 4 and 3", state: "From 4, set dist[3] = 4. From 3, set dist[5] = 5.", explanation: "The route 1 -> 4 -> 3 -> 5 costs 1 + 3 + 1.", variables: { dist5: "5", parent5: "3" } },
        { title: "Reconstruct path", state: "Trace parent from 5 to 3 to 4 to 1, then reverse.", explanation: "The parent array turns shortest distance into the actual shortest path.", variables: { answer: "1->4->3->5" } },
      ],
      closingInsight: "Weighted shortest path is Dijkstra for the cost, plus parents if the problem wants the route, not just the number.",
