function hasUsefulStoryDryRun(value: AlgorithmStoryDryRun | undefined) {
  return Boolean(
    value?.sampleInput?.trim() &&
      value?.sampleOutput?.trim() &&
      value?.closingInsight?.trim() &&
      Array.isArray(value.steps) &&
      value.steps.length >= 4 &&
      value.steps.every((step) => step.title?.trim() && step.state?.trim() && step.explanation?.trim())
  );
}

function buildStoryDryRun(algorithm: AlgorithmEntry, approach: AlgorithmApproach): AlgorithmStoryDryRun {
  const familyKey = detectFamily(algorithm, approach);
  const family = familyExplanations[familyKey];
  const seed = storySeeds[familyKey];
  const title = clean(algorithm.title);
  const approachName = clean(approach.name || "selected approach");
  const topic = clean(algorithm.topic || algorithm.category || "this topic");
  const dryRunLines = family.dryRun.length >= 4 ? family.dryRun.slice(0, 4) : familyExplanations.general.dryRun.slice(0, 4);
  const stepTitles = ["First move", "Decision point", "State update", "Check the answer"];

  return {
    sampleInput: `${seed.sampleInput}. This mini-run is intentionally small for ${title}.`,
    sampleOutput: seed.sampleOutput,
    steps: [
      {
        title: "Set the scene",
        state: `Pattern: ${family.label}. Topic: ${topic}.`,
        explanation: `${title} should first feel like a small story, not a wall of code. With ${approachName}, keep only the state that can still affect the answer.`,
        variables: seed.frames[0],
      },
      ...dryRunLines.map((line, index) => ({
        title: stepTitles[index] || `Step ${index + 1}`,
        state: line,
        explanation: `Read this as page ${index + 1} of the run: perform one decision, say why it is legal, then carry the updated state forward before looking at the next item.`,
        variables: seed.frames[Math.min(index, seed.frames.length - 1)],
      })),
      {
        title: "Final reveal",
        state: seed.sampleOutput,
        explanation: `The final answer should now feel earned: every update followed the same rule, and the invariant stayed true for ${title}.`,
        variables: seed.frames[seed.frames.length - 1],
      },
    ],
    closingInsight: `For a harder version of ${title}, do not memorize the code first. Re-run this small story, name the state variables out loud, and then translate those variables into ${approachName}.`,
  };
}
function clean(value: string) {
  return value
    .replace(/```[\s\S]*?```/g, " ")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/[^\x09\x0A\x0D\x20-\x7E]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}
